using UnityEngine;
using UnityEngine.UI;
using UnityEditor;
using TowerDefense.UI;
using TowerDefense.Data;

public static class CreateQuestPanelUI
{
    [MenuItem("Tools/Create QuestPanel UI")]
    public static void Create()
    {
        var canvas = GameObject.Find("Canvas")?.GetComponent<Canvas>();
        if (canvas == null) { Debug.LogError("Canvas not found"); return; }

        var canvasRect = canvas.GetComponent<RectTransform>();
        float canvasW = canvasRect.rect.width;
        float canvasH = canvasRect.rect.height;

        // === QuestPanel Root ===
        var questPanelRoot = new GameObject("QuestPanel");
        questPanelRoot.transform.SetParent(canvas.transform, false);
        var rootRect = questPanelRoot.AddComponent<RectTransform>();
        rootRect.anchorMin = Vector2.zero;
        rootRect.anchorMax = Vector2.one;
        rootRect.offsetMin = Vector2.zero;
        rootRect.offsetMax = Vector2.zero;
        questPanelRoot.SetActive(false);

        // Semi-transparent overlay
        var overlayImg = questPanelRoot.AddComponent<Image>();
        overlayImg.color = new Color(0, 0, 0, 0.4f);

        var rootCanvasGroup = questPanelRoot.AddComponent<CanvasGroup>();
        rootCanvasGroup.blocksRaycasts = true;

        // === Frame (centered rounded rect) ===
        var frame = CreateUIObject("Frame", questPanelRoot);
        var frameRect = frame.GetComponent<RectTransform>();
        frameRect.anchorMin = new Vector2(0.1f, 0.08f);
        frameRect.anchorMax = new Vector2(0.9f, 0.92f);
        frameRect.offsetMin = Vector2.zero;
        frameRect.offsetMax = Vector2.zero;
        var frameImg = frame.AddComponent<Image>();
        frameImg.color = new Color(0.99f, 0.96f, 0.89f, 1f); // Cream background
        frameImg.type = Image.Type.Sliced;

        // Green border effect via outline
        var frameOutline = frame.AddComponent<Outline>();
        frameOutline.effectColor = new Color(0.2f, 0.55f, 0.15f, 1f);
        frameOutline.effectDistance = new Vector2(6, -6);

        // === TitleBar ===
        var titleBar = CreateUIObject("TitleBar", frame);
        var titleBarRect = titleBar.GetComponent<RectTransform>();
        titleBarRect.anchorMin = new Vector2(0.1f, 1f);
        titleBarRect.anchorMax = new Vector2(0.9f, 1f);
        titleBarRect.offsetMin = new Vector2(0, -60);
        titleBarRect.offsetMax = new Vector2(0, 10);
        var titleBarImg = titleBar.AddComponent<Image>();
        titleBarImg.color = new Color(0.25f, 0.6f, 0.2f, 1f); // Green banner
        var titleBarOutline = titleBar.AddComponent<Outline>();
        titleBarOutline.effectColor = new Color(0.15f, 0.4f, 0.1f, 1f);
        titleBarOutline.effectDistance = new Vector2(2, -2);

        // Title Text
        var titleText = CreateUIObject("TitleText", titleBar);
        var titleTextRect = titleText.GetComponent<RectTransform>();
        titleTextRect.anchorMin = Vector2.zero;
        titleTextRect.anchorMax = Vector2.one;
        titleTextRect.offsetMin = Vector2.zero;
        titleTextRect.offsetMax = Vector2.zero;
        var titleTxt = titleText.AddComponent<Text>();
        titleTxt.text = "任务";
        titleTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        titleTxt.fontSize = 28;
        titleTxt.fontStyle = FontStyle.Bold;
        titleTxt.color = Color.white;
        titleTxt.alignment = TextAnchor.MiddleCenter;
        var titleShadow = titleText.AddComponent<Shadow>();
        titleShadow.effectColor = new Color(0, 0, 0, 0.5f);
        titleShadow.effectDistance = new Vector2(2, -2);

        // Close Button
        var closeBtn = CreateUIObject("CloseButton", titleBar);
        var closeBtnRect = closeBtn.GetComponent<RectTransform>();
        closeBtnRect.anchorMin = new Vector2(1f, 0.5f);
        closeBtnRect.anchorMax = new Vector2(1f, 0.5f);
        closeBtnRect.sizeDelta = new Vector2(45, 45);
        closeBtnRect.anchoredPosition = new Vector2(-30, 0);
        var closeBtnImg = closeBtn.AddComponent<Image>();
        closeBtnImg.color = new Color(1f, 0.8f, 0.1f, 1f); // Yellow circle
        var closeBtnOutline = closeBtn.AddComponent<Outline>();
        closeBtnOutline.effectColor = new Color(0.8f, 0.6f, 0f, 1f);
        closeBtnOutline.effectDistance = new Vector2(2, -2);
        var closeButton = closeBtn.AddComponent<Button>();
        var closeTxt = closeBtn.AddComponent<Text>();
        closeTxt.text = "✕";
        closeTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
        closeTxt.fontSize = 22;
        closeTxt.fontStyle = FontStyle.Bold;
        closeTxt.color = Color.white;
        closeTxt.alignment = TextAnchor.MiddleCenter;

        // === Content Area (Horizontal: Sidebar + List) ===
        var contentArea = CreateUIObject("ContentArea", frame);
        var contentAreaRect = contentArea.GetComponent<RectTransform>();
        contentAreaRect.anchorMin = new Vector2(0, 0);
        contentAreaRect.anchorMax = new Vector2(1, 1);
        contentAreaRect.offsetMin = new Vector2(10, 80);
        contentAreaRect.offsetMax = new Vector2(-10, -55);
        var hLayout = contentArea.AddComponent<HorizontalLayoutGroup>();
        hLayout.spacing = 8;
        hLayout.childAlignment = TextAnchor.MiddleLeft;
        hLayout.childControlWidth = true;
        hLayout.childControlHeight = true;
        hLayout.childForceExpandWidth = false;
        hLayout.childForceExpandHeight = true;
        hLayout.padding = new RectOffset(5, 5, 5, 5);

        // === Left Sidebar (Tabs) ===
        var sidebar = CreateUIObject("Sidebar", contentArea);
        var sidebarLayout = sidebar.AddComponent<VerticalLayoutGroup>();
        sidebarLayout.spacing = 6;
        sidebarLayout.childAlignment = TextAnchor.UpperCenter;
        sidebarLayout.childControlWidth = true;
        sidebarLayout.childControlHeight = false;
        sidebarLayout.childForceExpandWidth = true;
        sidebarLayout.childForceExpandHeight = false;
        sidebarLayout.padding = new RectOffset(2, 2, 5, 5);
        var sidebarLe = sidebar.AddComponent<LayoutElement>();
        sidebarLe.minWidth = 130;
        sidebarLe.preferredWidth = 130;

        // Create 4 tabs
        string[] tabNames = { "每日任务", "主线任务", "成就任务", "活动任务" };
        string[] tabIcons = { "📅", "🚩", "🏆", "🎁" };
        Button[] tabButtons = new Button[4];

        for (int i = 0; i < 4; i++)
        {
            var tab = CreateUIObject($"Tab_{tabNames[i]}", sidebar);
            var tabLe = tab.AddComponent<LayoutElement>();
            tabLe.minHeight = 65;
            tabLe.preferredHeight = 65;
            var tabImg = tab.AddComponent<Image>();
            tabImg.color = i == 0
                ? new Color(1f, 0.78f, 0.2f, 1f)  // Active: yellow/orange
                : new Color(0.3f, 0.6f, 0.3f, 1f); // Inactive: green

            var tabBtn = tab.AddComponent<Button>();
            tabButtons[i] = tabBtn;

            var tabOutline = tab.AddComponent<Outline>();
            tabOutline.effectColor = new Color(0, 0, 0, 0.2f);
            tabOutline.effectDistance = new Vector2(1, -1);

            // Tab content: icon + text
            var tabContent = CreateUIObject("Content", tab);
            var tabContentRect = tabContent.GetComponent<RectTransform>();
            tabContentRect.anchorMin = Vector2.zero;
            tabContentRect.anchorMax = Vector2.one;
            tabContentRect.offsetMin = new Vector2(8, 4);
            tabContentRect.offsetMax = new Vector2(-8, -4);

            var tabHLayout = tabContent.AddComponent<HorizontalLayoutGroup>();
            tabHLayout.spacing = 4;
            tabHLayout.childAlignment = TextAnchor.MiddleCenter;
            tabHLayout.childControlWidth = false;
            tabHLayout.childControlHeight = false;
            tabHLayout.childForceExpandWidth = false;
            tabHLayout.childForceExpandHeight = false;

            // Icon emoji
            var iconObj = CreateUIObject("Icon", tabContent);
            var iconLe = iconObj.AddComponent<LayoutElement>();
            iconLe.minWidth = 28;
            iconLe.minHeight = 28;
            var iconTxt = iconObj.AddComponent<Text>();
            iconTxt.text = tabIcons[i];
            iconTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            iconTxt.fontSize = 20;
            iconTxt.alignment = TextAnchor.MiddleCenter;

            // Text
            var labelObj = CreateUIObject("Label", tabContent);
            var labelLe = labelObj.AddComponent<LayoutElement>();
            labelLe.minWidth = 60;
            labelLe.minHeight = 28;
            var labelTxt = labelObj.AddComponent<Text>();
            labelTxt.text = tabNames[i];
            labelTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            labelTxt.fontSize = 14;
            labelTxt.fontStyle = FontStyle.Bold;
            labelTxt.color = Color.white;
            labelTxt.alignment = TextAnchor.MiddleLeft;

            // Red dot for first tab (daily tasks have notifications)
            if (i == 0)
            {
                var redDot = CreateUIObject("RedDot", tab);
                var redDotRect = redDot.GetComponent<RectTransform>();
                redDotRect.anchorMin = new Vector2(1f, 1f);
                redDotRect.anchorMax = new Vector2(1f, 1f);
                redDotRect.sizeDelta = new Vector2(12, 12);
                redDotRect.anchoredPosition = new Vector2(-5, -5);
                var redDotImg = redDot.AddComponent<Image>();
                redDotImg.color = new Color(1f, 0.2f, 0.2f, 1f);
            }
        }

        // === Right Content Area ===
        var rightArea = CreateUIObject("RightArea", contentArea);
        var rightLe = rightArea.AddComponent<LayoutElement>();
