        tagRect.pivot = new Vector2(0, 1);
        tagRect.sizeDelta = new Vector2(35, 18);
        tagRect.anchoredPosition = new Vector2(5, -3);
        var tagImg = tag.AddComponent<Image>();
        tagImg.color = new Color(1f, 0.3f, 0.3f, 1f);
        var tagTxt = tag.AddComponent<Text>();
        tagTxt.text = "new";
        tagTxt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
