        so.FindProperty("_rewardIcon").objectReferenceValue = riImg;
        so.FindProperty("_rewardText").objectReferenceValue = rtTxt;
        so.FindProperty("_actionButton").objectReferenceValue = abButton;
        so.FindProperty("_actionText").objectReferenceValue = abTxt;
        so.FindProperty("_tagObject").objectReferenceValue = tag;
        so.FindProperty("_tagText").objectReferenceValue = tagTxt;
        so.ApplyModifiedProperties();

        // Store prefab in scene (hide it)
        prefab.SetActive(false);
        prefab.transform.SetParent(null); // Root, not under canvas

        return prefab;
    }

    private static GameObject CreateUIObject(string name, GameObject parent)
    {
        var go = new GameObject(name);
        go.transform.SetParent(parent?.transform, false);
        var rect = go.AddComponent<RectTransform>();
        if (parent != null)
        {
            rect.anchorMin = Vector2.zero;
            rect.anchorMax = Vector2.one;
            rect.offsetMin = Vector2.zero;
            rect.offsetMax = Vector2.zero;
        }
        return go;
    }
}

