questPanelObj.SetActive(true);
var questPanel = questPanelObj.GetComponent<TowerDefense.UI.QuestPanel>();
if (questPanel == null) { UnityEngine.Debug.Log("QuestPanel component not found"); return; }

// Add click listener
questBtn.onClick.RemoveAllListeners();
questBtn.onClick.AddListener(questPanel.OpenQuest);

// Restore active state
questPanelObj.SetActive(false);

UnityEngine.Debug.Log("任务 button wired to QuestPanel.OpenQuest()");

